{
  "name": "hello-colors-app",
  "version": "1.0.0",
  "description": "Express + Tailwind project (build configured to emit compiled CSS to public/dist)",
  "main": "src/index.js",
  "scripts": {
    "start": "node src/index.js",
    "dev": "concurrently \"nodemon src/index.js\" \"tailwindcss -i ./src/styles.css -o ./public/dist/styles.css --watch\"",
    "build:css": "tailwindcss -i ./src/styles.css -o ./public/dist/styles.css --minify",
    "test": "node ./tests/test.js"
  },
  "keywords": [],
  "author": "",
  "license": "MIT",
  "dependencies": {
    "express": "^4.18.2"
  },
  "devDependencies": {
    "autoprefixer": "^10.4.14",
    "concurrently": "^7.6.0",
    "nodemon": "^2.0.22",
    "postcss": "^8.4.21",
    "tailwindcss": "^3.4.6"
  }
}

const express = require('express');
const path = require('path');

const app = express();
const PORT = process.env.PORT || 3000;

// Serve static files from public
app.use(express.static(path.join(__dirname, '..', 'public')));

// Simple API endpoint (future use)
app.get('/api/hello', (req, res) => {
  res.json({ message: 'Hello World' });
});

app.listen(PORT, () => {
  console.log(`Server listening on http://localhost:${PORT}`);
});

@tailwind base;
@tailwind components;
@tailwind utilities;

/* Add any custom styles here. The frontend UI will let you change text color classes. */

const fs = require('fs');
const assert = require('assert');

// package.json checks
const pkgRaw = fs.readFileSync('package.json', 'utf8');
const pkg = JSON.parse(pkgRaw);
assert.strictEqual(pkg.name, 'hello-colors-app', 'package.json name should be hello-colors-app');
assert.ok(pkg.scripts && typeof pkg.scripts === 'object', 'package.json should have scripts');
assert.ok(pkg.scripts['build:css'], 'package.json should have build:css script');
assert.ok(pkg.scripts['build:css'].includes('./public/dist/styles.css') || pkg.scripts['build:css'].includes('public/dist/styles.css'), 'build:css script should output to public/dist/styles.css');

// Check dev script watches the same output
assert.ok(pkg.scripts['dev'] && pkg.scripts['dev'].includes('public/dist/styles.css'), 'dev script should watch output to public/dist/styles.css');

// Check dependencies/devDependencies include tailwind/postcss/autoprefixer
const devDeps = pkg.devDependencies || {};
assert.ok(devDeps['tailwindcss'], 'tailwindcss should be in devDependencies');
assert.ok(devDeps['postcss'], 'postcss should be in devDependencies');
assert.ok(devDeps['autoprefixer'], 'autoprefixer should be in devDependencies');

// Check tailwind and postcss config files exist
assert.ok(fs.existsSync('tailwind.config.js'), 'tailwind.config.js must exist');
assert.ok(fs.existsSync('postcss.config.js'), 'postcss.config.js must exist');

// Check src/styles.css contains @tailwind directives
const styles = fs.readFileSync('src/styles.css', 'utf8');
assert.ok(/@tailwind\s+base/.test(styles), 'src/styles.css should contain @tailwind base');
assert.ok(/@tailwind\s+components/.test(styles), 'src/styles.css should contain @tailwind components');
assert.ok(/@tailwind\s+utilities/.test(styles), 'src/styles.css should contain @tailwind utilities');

console.log('All checks passed for Tailwind/PostCSS configuration.');
